const linkedinHtml = $('Scrape LinkedIn').first().json.data || '';
const infojobsHtml = $('Scrape InfoJobs').first().json.data || '';
const tecnoHtml = $('Scrape Tecnoempleo').first().json.data || '';
const indeedHtml = $('Scrape Indeed').first().json.data || '';

function extractJobs(html, source, baseUrl, titlePattern, linkPattern) {
  const jobs = [];
  const titles = [...html.matchAll(titlePattern)];
  const links = [...html.matchAll(linkPattern)];
  const count = Math.min(titles.length, links.length, 10);
  for (let i = 0; i < count; i++) {
    jobs.push({
      source,
      title: titles[i][1].replace(/<[^>]*>/g, '').trim(),
      url: links[i][1].startsWith('http') ? links[i][1] : baseUrl + links[i][1]
    });
  }
  return jobs;
}

const liJobs = extractJobs(linkedinHtml, 'LinkedIn', 'https://www.linkedin.com',
  /class="base-search-card__title"[^>]*>([^<]+)</gi,
  /href="(https:\/\/www\.linkedin\.com\/jobs\/view\/[^"]+)"/gi);

const ijJobs = extractJobs(infojobsHtml, 'InfoJobs', 'https://www.infojobs.net',
  /class="[^"]*js-o-link[^"]*"[^>]*>([^<]+)</gi,
  /href="(\/empleo\/[^"]+)"/gi);

const teJobs = extractJobs(tecnoHtml, 'Tecnoempleo', 'https://www.tecnoempleo.com',
  /<h3[^>]*class="[^"]*fs18[^"]*"[^>]*><a[^>]*>([^<]+)<\/a>/gi,
  /href="(\/oferta-trabajo\/[^"]+)"/gi);

const inJobs = extractJobs(indeedHtml, 'Indeed', 'https://es.indeed.com',
  /class="jobTitle"[^>]*><[^>]+>([^<]+)</gi,
  /href="(\/rc\/clk[^"]+)"/gi);

const allJobs = [...liJobs, ...ijJobs, ...teJobs, ...inJobs];
const today = new Date().toLocaleDateString('es-ES', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

return [{ json: { jobs: allJobs, total: allJobs.length, date: today } }];

const { jobs, total, date } = items[0].json;

if (total === 0) {
  return [{ json: { subject: 'Busqueda empleo — Sin resultados hoy', body: 'No se han encontrado ofertas nuevas hoy.', total: 0 } }];
}

const bySource = {};
jobs.forEach(j => {
  if (!bySource[j.source]) bySource[j.source] = [];
  bySource[j.source].push(j);
});

let body = `RESUMEN DIARIO DE OFERTAS\n${date}\n${'='.repeat(50)}\n\nTotal: ${total} ofertas nuevas\n\n`;

Object.entries(bySource).forEach(([source, sourceJobs]) => {
  body += `── ${source.toUpperCase()} (${sourceJobs.length} ofertas) ──\n`;
  sourceJobs.forEach((j, i) => {
    body += `${i + 1}. ${j.title}\n   ${j.url}\n\n`;
  });
});

body += `${'='.repeat(50)}\nProximos pasos:\n1. Selecciona las mejores 3-5 ofertas\n2. Genera carta de presentacion: POST https://nameek.app.n8n.cloud/webhook/generate-cover-letter\n3. Registra candidatura: POST https://nameek.app.n8n.cloud/webhook/track-application\n\nBuena suerte!`;

return [{ json: { subject: `Ofertas empleo — ${total} nuevas (${date})`, body, total } }];

const response = items[0].json;
const content = response.content && response.content[0] ? response.content[0].text : 'Error al generar carta';
const jobTitle = $('Cover Letter Webhook').first().json.body.job_title;
const company = $('Cover Letter Webhook').first().json.body.company_name;
return [{ json: { cover_letter: content, job_title: jobTitle, company, subject: `Carta presentacion — ${jobTitle} en ${company}` } }];

const data = items[0].json;
const now = new Date();
const followUpDate = new Date(now.getTime() + 5 * 24 * 60 * 60 * 1000);
const pad = (n) => String(n).padStart(2, '0');
const formatDate = (d) => `${pad(d.getDate())}/${pad(d.getMonth()+1)}/${d.getFullYear()}`;
return [{ json: {
  company: data.body.company || 'Sin especificar',
  job_title: data.body.job_title || 'Sin especificar',
  job_url: data.body.job_url || '',
  platform: data.body.platform || 'Otro',
  notes: data.body.notes || '',
  date_applied: formatDate(now),
  followup_date: formatDate(followUpDate),
  status: 'Enviada',
  followup_ms: followUpDate.getTime() - now.getTime()
}}];

